import base64
import pickle
import json
import hashlib
import hmac
from typing import Any, Dict
import os

ALLOWED_CLASSES = {
    'builtins.dict',
    'builtins.list',
    'builtins.str',
    'builtins.int',
    'builtins.float',
    'builtins.bool',
    'builtins.tuple',
    'builtins.set',
    'builtins.frozenset',
    'builtins.bytes',
    'builtins.bytearray',
    'datetime.datetime',
    'datetime.date',
    'datetime.time',
    'datetime.timedelta',
    'decimal.Decimal',
    'uuid.UUID',
}

HMAC_SECRET = os.environ.get('HMAC_SECRET', 'your-secret-key-here')

class RestrictedUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        full_name = f"{module}.{name}"
        if full_name not in ALLOWED_CLASSES:
            raise pickle.UnpicklingError(f"Class {full_name} is not allowed for deserialization")
        return super().find_class(module, name)

def verify_hmac(data: bytes, signature: str) -> bool:
    expected_signature = hmac.new(
        HMAC_SECRET.encode(),
        data,
        hashlib.sha256
    ).hexdigest()
    return hmac.compare_digest(expected_signature, signature)

def safe_pickle_loads(data: bytes) -> Any:
    return RestrictedUnpickler(io.BytesIO(data)).load()

def process_batch_job(job_data: Dict[str, Any]) -> Dict[str, Any]:
    job_type = job_data.get('type', 'unknown')
    job_id = job_data.get('job_id', 'unknown')
    payload = job_data.get('payload', {})
    
    result = {
        'job_id': job_id,
        'job_type': job_type,
        'status': 'success',
        'processed_items': 0
    }
    
    if job_type == 'data_processing':
        items = payload.get('items', [])
        result['processed_items'] = len(items)
        result['summary'] = f"Processed {len(items)} items"
    elif job_type == 'aggregation':
        values = payload.get('values', [])
        result['processed_items'] = len(values)
        result['total'] = sum(values) if values else 0
    elif job_type == 'transformation':
        data = payload.get('data', [])
        result['processed_items'] = len(data)
        result['transformed'] = True
    else:
        result['status'] = 'unknown_job_type'
    
    return result

def pubsub_handler(event, context):
    import io
    
    try:
        pubsub_message = base64.b64decode(event['data'])
        
        try:
            message_wrapper = json.loads(pubsub_message.decode('utf-8'))
        except (json.JSONDecodeError, UnicodeDecodeError):
            return {
                'status': 'error',
                'message': 'Invalid message format - expected JSON'
            }
        
        if 'signature' not in message_wrapper or 'data' not in message_wrapper:
            return {
                'status': 'error',
                'message': 'Message missing required fields (signature, data)'
            }
        
        pickled_data = base64.b64decode(message_wrapper['data'])
        signature = message_wrapper['signature']
        
        if not verify_hmac(pickled_data, signature):
            return {
                'status': 'error',
                'message': 'HMAC verification failed - message rejected'
            }
        
        max_size = 10 * 1024 * 1024  # 10MB
        if len(pickled_data) > max_size:
            return {
                'status': 'error',
                'message': f'Payload too large: {len(pickled_data)} bytes (max: {max_size})'
            }
        
        try:
            job_data = safe_pickle_loads(pickled_data)
        except pickle.UnpicklingError as e:
            return {
                'status': 'error',
                'message': f'Deserialization failed: {str(e)}'
            }
        
        if not isinstance(job_data, dict):
            return {
                'status': 'error',
                'message': 'Deserialized data must be a dictionary'
            }
        
        result = process_batch_job(job_data)
        
        return {
            'status': 'success',
            'result': result,
            'message': f"Job {result.get('job_id')} processed successfully"
        }
        
    except Exception as e:
        return {
            'status': 'error',
            'message': f'Unexpected error: {str(e)}'
        }

def main(event, context):
    return pubsub_handler(event, context)